from Crypto.Cipher import Fernet

# Generate and save a key securely
def generate_key():
    key = Fernet.generate_key()
    with open("secret.key", "wb") as key_file:
        key_file.write(key)

# Load the encryption key from file
def load_key():
    return open("secret.key", "rb").read()

# Encrypt credit card number
def encrypt_credit_card(credit_card_number):
    key = load_key()
    cipher_suite = Fernet(key)
    encrypted_card = cipher_suite.encrypt(credit_card_number.encode())
    return encrypted_card

# Decrypt credit card number
def decrypt_credit_card(encrypted_card):
    key = load_key()
    cipher_suite = Fernet(key)
    decrypted_card = cipher_suite.decrypt(encrypted_card).decode()
    return decrypted_card

# Example usage
if __name__ == "__main__":
    generate_key()  # Run this once to create the secret.key file
    credit_card_number = "1234-5678-9012-3456"
    encrypted_card = encrypt_credit_card(credit_card_number)
    print("Encrypted:", encrypted_card)
    decrypted_card = decrypt_credit_card(encrypted_card)
    print("Decrypted:", decrypted_card)